import{_ as e,o as l,c as a,a7 as d}from"./chunks/framework.C5fSpjcB.js";const g=JSON.parse('{"title":"戦闘システム","description":"","frontmatter":{},"headers":[],"relativePath":"ja/systems/combat.md","filePath":"ja/systems/combat.md","lastUpdated":1775394001000}'),i={name:"ja/systems/combat.md"};function s(r,t,n,h,y,x){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="戦闘システム" tabindex="-1">戦闘システム <a class="header-anchor" href="#戦闘システム" aria-label="Permalink to &quot;戦闘システム&quot;">​</a></h1><p>忘却前夜（Morimens）の戦闘システムについて解説します。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><p>ターン制コマンドバトル方式です。各キャラクターは速度順に行動し、コマンドを選択して戦闘を進めます。</p><h3 id="行動の種類" tabindex="-1">行動の種類 <a class="header-anchor" href="#行動の種類" aria-label="Permalink to &quot;行動の種類&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">コマンド</th><th style="text-align:left;">説明</th><th style="text-align:center;">SP消費</th></tr></thead><tbody><tr><td style="text-align:left;">通常攻撃</td><td style="text-align:left;">基本攻撃。SPを回復する</td><td style="text-align:center;">0（+10回復）</td></tr><tr><td style="text-align:left;">スキル1</td><td style="text-align:left;">戦闘スキル。様々な効果</td><td style="text-align:center;">20〜40</td></tr><tr><td style="text-align:left;">スキル2</td><td style="text-align:left;">戦闘スキル。様々な効果</td><td style="text-align:center;">30〜50</td></tr><tr><td style="text-align:left;">奥義</td><td style="text-align:left;">必殺技。奥義ゲージ100%で発動</td><td style="text-align:center;">0（ゲージ消費）</td></tr><tr><td style="text-align:left;">防御</td><td style="text-align:left;">ダメージ50%軽減、SP+5</td><td style="text-align:center;">0</td></tr></tbody></table><h2 id="spシステム" tabindex="-1">SPシステム <a class="header-anchor" href="#spシステム" aria-label="Permalink to &quot;SPシステム&quot;">​</a></h2><ul><li>各キャラクターの最大SP: 100</li><li>戦闘開始時のSP: 50</li><li>通常攻撃でSP +10回復</li><li>被弾時にSP +5回復</li><li>一部装備やパッシブでSP回復量が変動</li></ul><h2 id="奥義ゲージ" tabindex="-1">奥義ゲージ <a class="header-anchor" href="#奥義ゲージ" aria-label="Permalink to &quot;奥義ゲージ&quot;">​</a></h2><ul><li>最大値: 100%</li><li>ダメージを与える・受けるたびに蓄積</li><li>キャラクターごとに蓄積速度が異なる</li><li>100%到達で奥義発動可能（任意のタイミングで使用可能）</li><li>奥義発動中は他のキャラクターの行動が中断されない</li></ul><div class="tip custom-block"><p class="custom-block-title">ヒント</p><p>奥義ゲージは通常攻撃よりスキルで攻撃した方が多く蓄積されます。SPと奥義ゲージのバランスを考えましょう。</p></div><h2 id="属性相性" tabindex="-1">属性相性 <a class="header-anchor" href="#属性相性" aria-label="Permalink to &quot;属性相性&quot;">​</a></h2><p>属性相性によりダメージが増減します。</p><table tabindex="0"><thead><tr><th style="text-align:left;">相性</th><th style="text-align:center;">ダメージ倍率</th></tr></thead><tbody><tr><td style="text-align:left;">有利属性</td><td style="text-align:center;">×1.3（+30%）</td></tr><tr><td style="text-align:left;">等倍</td><td style="text-align:center;">×1.0</td></tr><tr><td style="text-align:left;">不利属性</td><td style="text-align:center;">×0.7（-30%）</td></tr></tbody></table><p>詳細な属性相性表は<a href="./../characters/team-building.html">編成ガイド</a>を参照してください。</p><h2 id="状態異常" tabindex="-1">状態異常 <a class="header-anchor" href="#状態異常" aria-label="Permalink to &quot;状態異常&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">状態異常</th><th style="text-align:left;">効果</th><th style="text-align:center;">持続</th></tr></thead><tbody><tr><td style="text-align:left;">燃焼</td><td style="text-align:left;">毎ターン最大HPの5%ダメージ</td><td style="text-align:center;">3ターン</td></tr><tr><td style="text-align:left;">凍結</td><td style="text-align:left;">行動不能</td><td style="text-align:center;">1ターン</td></tr><tr><td style="text-align:left;">感電</td><td style="text-align:left;">スキル使用時にダメージ</td><td style="text-align:center;">2ターン</td></tr><tr><td style="text-align:left;">毒</td><td style="text-align:left;">毎ターン最大HPの3%ダメージ</td><td style="text-align:center;">4ターン</td></tr><tr><td style="text-align:left;">暗闇</td><td style="text-align:left;">命中率-30%</td><td style="text-align:center;">2ターン</td></tr><tr><td style="text-align:left;">スタン</td><td style="text-align:left;">行動不能</td><td style="text-align:center;">1ターン</td></tr><tr><td style="text-align:left;">沈黙</td><td style="text-align:left;">スキル使用不可</td><td style="text-align:center;">2ターン</td></tr></tbody></table><h2 id="バフ・デバフ" tabindex="-1">バフ・デバフ <a class="header-anchor" href="#バフ・デバフ" aria-label="Permalink to &quot;バフ・デバフ&quot;">​</a></h2><h3 id="主なバフ" tabindex="-1">主なバフ <a class="header-anchor" href="#主なバフ" aria-label="Permalink to &quot;主なバフ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">バフ</th><th style="text-align:left;">効果</th><th style="text-align:left;">付与者例</th></tr></thead><tbody><tr><td style="text-align:left;">攻撃力UP</td><td style="text-align:left;">攻撃力+30%</td><td style="text-align:left;"><span class="rarity-sr">フレイヤ</span></td></tr><tr><td style="text-align:left;">防御力UP</td><td style="text-align:left;">防御力+30%</td><td style="text-align:left;"><span class="rarity-ssr">ラグナ</span></td></tr><tr><td style="text-align:left;">クリ率UP</td><td style="text-align:left;">クリティカル率+15%</td><td style="text-align:left;"><span class="rarity-sr">ミレーユ</span></td></tr><tr><td style="text-align:left;">シールド</td><td style="text-align:left;">一定量のダメージを吸収</td><td style="text-align:left;"><span class="rarity-ssr">セレスティア</span></td></tr><tr><td style="text-align:left;">リジェネ</td><td style="text-align:left;">毎ターンHP回復</td><td style="text-align:left;"><span class="rarity-sr">フレイヤ</span></td></tr></tbody></table><h3 id="主なデバフ" tabindex="-1">主なデバフ <a class="header-anchor" href="#主なデバフ" aria-label="Permalink to &quot;主なデバフ&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">デバフ</th><th style="text-align:left;">効果</th><th style="text-align:left;">付与者例</th></tr></thead><tbody><tr><td style="text-align:left;">攻撃力DOWN</td><td style="text-align:left;">攻撃力-30%</td><td style="text-align:left;"><span class="rarity-sr">アリア</span></td></tr><tr><td style="text-align:left;">防御力DOWN</td><td style="text-align:left;">防御力-30%</td><td style="text-align:left;"><span class="rarity-ssr">ノワール</span></td></tr><tr><td style="text-align:left;">速度DOWN</td><td style="text-align:left;">行動順が遅くなる</td><td style="text-align:left;"><span class="rarity-sr">リーン</span></td></tr><tr><td style="text-align:left;">挑発</td><td style="text-align:left;">挑発者を優先攻撃</td><td style="text-align:left;"><span class="rarity-ssr">ラグナ</span></td></tr></tbody></table><h2 id="ブレイクシステム" tabindex="-1">ブレイクシステム <a class="header-anchor" href="#ブレイクシステム" aria-label="Permalink to &quot;ブレイクシステム&quot;">​</a></h2><p>敵にはブレイクゲージが存在します。</p><ol><li>弱点属性で攻撃するとブレイクゲージが蓄積</li><li>ゲージが満タンになると「ブレイク状態」に移行</li><li>ブレイク中は防御力大幅ダウン＋1ターン行動不能</li><li>ブレイク中のダメージは <strong>×1.5倍</strong></li></ol><div class="warning custom-block"><p class="custom-block-title">注意</p><p>ボスのブレイクゲージは大量に蓄積が必要です。チーム全体で弱点属性を突く編成が有効です。</p></div><h2 id="オート戦闘" tabindex="-1">オート戦闘 <a class="header-anchor" href="#オート戦闘" aria-label="Permalink to &quot;オート戦闘&quot;">​</a></h2><ul><li>メニューからオートモードをON/OFF可能</li><li>オート時はAIが最適な行動を自動選択</li><li>倍速機能: ×1、×2、×3から選択可能</li><li>掃討（スキップ）: ★3クリア済みステージで使用可能</li></ul><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./../characters/team-building.html">編成ガイド</a></li><li><a href="./../characters/">キャラクター図鑑</a></li><li><a href="./../stages/challenge.html">チャレンジ</a></li></ul>',30)])])}const f=e(i,[["render",s]]);export{g as __pageData,f as default};
